+                performance) REGEX='cache|optim|reduce|memory|latency|perf|speed|bundle|lazy|chunk' ;;
+                ci_cd) REGEX='ci|workflow|pipeline|action|build|release|deploy|docker|helm' ;;
+                documentation) REGEX='doc|readme|guide|example|tutorial|changelog|comment' ;;
               esac
-              COUNT=$(jq -r '.title' "$FILE" 2>/dev/null | grep -ciE "$REGEX" || echo 0)
+              COUNT=$(echo "$TITLES" | grep -ciE "$REGEX" 2>/dev/null || true)
+              COUNT=${COUNT:-0}
               PATTERNS["${REPO}:${PATTERN}"]=$COUNT
+              [ "$COUNT" -gt 0 ] && echo "  $PATTERN: $COUNT"
             done

             # Find notable PRs (ones with interesting titles)
-            jq -r 'select(.title | test("error|test|security|perf|observ|metric"; "i")) | "- [\(.title)](\(.url)) — *\("'"$REPO"'")*"' "$FILE" 2>/dev/null | head -3 >> /tmp/cncf-notable.md
+            jq -r '.[] | select(.title | test("error|test|security|perf|observ|metric|a11y|accessib|component|hook|react|typescript|css|style|ui|dashboard|frontend"; "i")) | "- [\(.title)](\(.url)) — *'"$REPO"'*"' "$FILE" 2>/dev/null | head -5 >> /tmp/cncf-notable.md

             sleep 2  # Rate limiting
           done
